"use strict";(globalThis.webpackChunkanomaly_detection_docs=globalThis.webpackChunkanomaly_detection_docs||[]).push([[887],{2003(a){a.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"referenceSidebar":[{"type":"link","href":"/anomaly-detection-atlas/attack-activity-log-source-catalog","label":"Suspicious and Malicious Activity by MITRE ATT&CK","docId":"attack-activity-log-source-catalog","unlisted":false},{"type":"link","href":"/anomaly-detection-atlas/attack-basic-detection-rule-catalog","label":"Basic Detection Rules by MITRE ATT&CK TTP","docId":"attack-basic-detection-rule-catalog","unlisted":false},{"type":"link","href":"/anomaly-detection-atlas/attack-statistical-anomaly-mapping","label":"Suspicious and Malicious Activity Explained by Statistical Anomalies","docId":"attack-statistical-anomaly-mapping","unlisted":false},{"type":"link","href":"/anomaly-detection-atlas/statistical-anomaly-taxonomy","label":"Statistical Anomaly Taxonomy","docId":"statistical-anomaly-taxonomy","unlisted":false},{"type":"link","href":"/anomaly-detection-atlas/security-log-source-taxonomy","label":"Vendor-Neutral Security Log Source Taxonomy","docId":"security-log-source-taxonomy","unlisted":false}]},"docs":{"attack-activity-log-source-catalog":{"id":"attack-activity-log-source-catalog","title":"Suspicious and Malicious Activity by MITRE ATT&CK","description":"This catalog describes observable suspicious and malicious activity aligned to the current MITRE ATT&CK Enterprise tactics and techniques. Each activity links directly to the vendor-neutral log sources that can report it.","sidebar":"referenceSidebar"},"attack-basic-detection-rule-catalog":{"id":"attack-basic-detection-rule-catalog","title":"Basic Detection Rules by MITRE ATT&CK TTP","description":"This catalog provides vendor-neutral algorithmic logic for basic deterministic detection rules mapped to MITRE ATT&CK Enterprise techniques and sub-techniques. Rules use signatures, fixed thresholds, allowlists, denylists, state changes, and bounded-window correlations. They do not depend on learned baselines or statistical anomaly models.","sidebar":"referenceSidebar"},"attack-statistical-anomaly-mapping":{"id":"attack-statistical-anomaly-mapping","title":"Suspicious and Malicious Activity Explained by Statistical Anomalies","description":"This catalog explains how observable suspicious and malicious activity can manifest as statistical anomalies. It connects ATT&CK-aligned activity to the reference population, expected behavior, measurable deviation, applicable statistical anomaly types, and supporting log sources.","sidebar":"referenceSidebar"},"security-log-source-taxonomy":{"id":"security-log-source-taxonomy","title":"Vendor-Neutral Security Log Source Taxonomy","description":"This document catalogs security-relevant log and telemetry source types without mapping them to vendors, detection rules, anomalies, or threat frameworks. Each entry describes what the source records and the kinds of activity it can report.","sidebar":"referenceSidebar"},"statistical-anomaly-taxonomy":{"id":"statistical-anomaly-taxonomy","title":"Statistical Anomaly Taxonomy","description":"This document lists statistically relevant anomaly types without tying them to any specific application domain. An anomaly is an observation, group of observations, relationship, sequence, or distributional state that deviates meaningfully from an appropriate reference model.","sidebar":"referenceSidebar"}}}}')}}]);